const results1 = $('HTTP Request15').first().json.results;
const results2 = $input.first().json.results;

const allResults = [...results1, ...results2];

const formatted = allResults.map(r =>
  `URL: ${r.url}\nTITLE: ${r.title}\nCONTENT: ${r.content}`
).join('\n\n---\n\n');

const coin_name = $('HTTP Request15').first().json.query.split(' ')[0];

return [{
  json: {
    coin_name: coin_name,
    tavilyContext: formatted
  }
}];

