const tokenomic = $('Tokenomic & Santé Financière').first().json.text;
const conclusion = $('Conclusion').first().json.text;
const coin_name = $json.coin_name;

const fullHtml = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body>
${intro}
<hr>
${narratif}
