const html = $input.first().json.html;
const coin_name = $input.first().json.coin_name;

const binaryData = Buffer.from(html, 'utf8');

return [{
  json: { coin_name },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/html',
      fileName: `Analyse ${coin_name}.html`
    }
  }
}];
